import WebPageHeaderInfo from './components/WebPageHeaderInfo';
import WebPageHeaderNavigator from './components/WebPageHeaderNavigator';
import './WebPageHeader.css';
import './WebPageHeaderNavigator.css';
import './WebPageHeaderInfo.css';


const WebPageHeader = () => {
    return (
        <header>
            <left>
            <WebPageHeaderInfo currentPageName="Home"
                githubURL="www.github.com"
                githubPagesURL="www.github.com"
                domainName="www.unix69.github.io"
                webPageHeaderInfoClass="web-page-header-info"
                webPageHeaderInfoDomainInfoClass="web-page-header-info-domain-info"
                webPageHeaderInfoDomainLogoClass="web-page-header-info-domain-logo"
                webPageHeaderInfoGitHubInfoClass="web-page-header-info-github-info"
                webPageHeaderInfoGitHubLogoClass="web-page-header-info-github-logo"
                webPageHeaderInfoBackgroundImageClass="web-page-header-info-background-image"
            />
            <WebPageHeaderNavigator class="WebPageHeaderNavigator"/>
        </left>
        </header>
    );
};

export default WebPageHeader;
